#include "biblia.h"

void Biblia::Carregar2Timoteo(Biblia* b) {
    b->dados[TIMOTEO2].nome = wxT("2 Timoteo");

    b->dados[TIMOTEO2].capitulos[1].versos[1] = wxT("Paulo, apóstolo de Cristo Jesus pela vontade de Deus, segundo a promessa da vida que está em Cristo Jesus,");
    b->dados[TIMOTEO2].capitulos[1].versos[2] = wxT("a Timóteo, amado filho: Graça, misericórdia e paz da parte de Deus Pai e de Cristo Jesus nosso Senhor.");
    b->dados[TIMOTEO2].capitulos[1].versos[3] = wxT("Dou graças a Deus, a quem desde os meus antepassados sirvo com uma consciência pura, de que sem cessar faço menção de ti em minhas súplicas de noite e de dia;");
    b->dados[TIMOTEO2].capitulos[1].versos[4] = wxT("e, recordando-me das tuas lágrimas, desejo muito ver-te, para me encher de gozo;");
    b->dados[TIMOTEO2].capitulos[1].versos[5] = wxT("trazendo à memória a fé não fingida que há em ti, a qual habitou primeiro em tua avó Loide, e em tua mãe Eunice e estou certo de que também habita em ti.");
    b->dados[TIMOTEO2].capitulos[1].versos[6] = wxT("Por esta razão te lembro que despertes o dom de Deus, que há em ti pela imposição das minhas mãos.");
    b->dados[TIMOTEO2].capitulos[1].versos[7] = wxT("Porque Deus não nos deu o espírito de covardia, mas de poder, de amor e de moderação.");
    b->dados[TIMOTEO2].capitulos[1].versos[8] = wxT("Portanto não te envergonhes do testemunho de nosso Senhor, nem de mim, que sou prisioneiro seu; antes participa comigo dos sofrimentos do evangelho segundo o poder de Deus,");
    b->dados[TIMOTEO2].capitulos[1].versos[9] = wxT("que nos salvou, e chamou com uma santa vocação, não segundo as nossas obras, mas segundo o seu próprio propósito e a graça que nos foi dada em Cristo Jesus antes dos tempos eternos,");
    b->dados[TIMOTEO2].capitulos[1].versos[10] = wxT("e que agora se manifestou pelo aparecimento de nosso Salvador Cristo Jesus, o qual destruiu a morte, e trouxe à luz a vida e a imortalidade pelo evangelho,");
    b->dados[TIMOTEO2].capitulos[1].versos[11] = wxT("do qual fui constituído pregador, apóstolo e mestre.");
    b->dados[TIMOTEO2].capitulos[1].versos[12] = wxT("Por esta razão sofro também estas coisas, mas não me envergonho; porque eu sei em quem tenho crido, e estou certo de que ele é poderoso para guardar o meu depósito até aquele dia.");
    b->dados[TIMOTEO2].capitulos[1].versos[13] = wxT("Conserva o modelo das sãs palavras que de mim tens ouvido na fé e no amor que há em Cristo Jesus;");
    b->dados[TIMOTEO2].capitulos[1].versos[14] = wxT("guarda o bom depósito com o auxílio do Espírito Santo, que habita em nós.");
    b->dados[TIMOTEO2].capitulos[1].versos[15] = wxT("Bem sabes isto, que me abandonaram todos os que estão na Ásia, entre eles Fígelo e Hermógenes.");
    b->dados[TIMOTEO2].capitulos[1].versos[16] = wxT("O Senhor conceda misericórdia à casa de Onesíforo, porque muitas vezes ele me recreou, e não se envergonhou das minhas cadeias;");
    b->dados[TIMOTEO2].capitulos[1].versos[17] = wxT("antes quando veio a Roma, diligentemente me procurou e me achou.");
    b->dados[TIMOTEO2].capitulos[1].versos[18] = wxT("O Senhor lhe conceda que naquele dia ache misericórdia diante do Senhor. E quantos serviços prestou em Éfeso melhor o sabes tu.");

    b->dados[TIMOTEO2].capitulos[2].versos[1] = wxT("Tu, pois, meu filho, fortifica-te na graça que há em Cristo Jesus;");
    b->dados[TIMOTEO2].capitulos[2].versos[2] = wxT("e o que de mim ouviste de muitas testemunhas, transmite-o a homens fiéis, que sejam idôneos para também ensinarem os outros.");
    b->dados[TIMOTEO2].capitulos[2].versos[3] = wxT("Sofre comigo como bom soldado de Cristo Jesus.");
    b->dados[TIMOTEO2].capitulos[2].versos[4] = wxT("Nenhum soldado em serviço se embaraça com negócios desta vida, a fim de agradar àquele que o alistou para a guerra.");
    b->dados[TIMOTEO2].capitulos[2].versos[5] = wxT("E também se um atleta lutar nos jogos públicos, não será coroado se não lutar legitimamente.");
    b->dados[TIMOTEO2].capitulos[2].versos[6] = wxT("O lavrador que trabalha deve ser o primeiro a gozar dos frutos.");
    b->dados[TIMOTEO2].capitulos[2].versos[7] = wxT("Considera o que digo, porque o Senhor te dará entendimento em tudo.");
    b->dados[TIMOTEO2].capitulos[2].versos[8] = wxT("Lembra-te de Jesus Cristo, ressurgido dentre os mortos, descendente de Davi, segundo o meu evangelho,");
    b->dados[TIMOTEO2].capitulos[2].versos[9] = wxT("pelo qual sofro a ponto de ser preso como malfeitor; mas a palavra de Deus não está presa.");
    b->dados[TIMOTEO2].capitulos[2].versos[10] = wxT("Por isso, tudo suporto por amor dos eleitos, para que também eles alcancem a salvação que há em Cristo Jesus com glória eterna.");
    b->dados[TIMOTEO2].capitulos[2].versos[11] = wxT("Fiel é esta palavra: Se, pois, já morremos com ele, também com ele viveremos;");
    b->dados[TIMOTEO2].capitulos[2].versos[12] = wxT("se perseveramos, com ele também reinaremos; se o negarmos, também ele nos negará;");
    b->dados[TIMOTEO2].capitulos[2].versos[13] = wxT("se somos infiéis, ele permanece fiel; porque não pode negar-se a si mesmo.");
    b->dados[TIMOTEO2].capitulos[2].versos[14] = wxT("Lembra-lhes estas coisas, conjurando-os diante de Deus que não tenham contendas de palavras, que para nada aproveitam, senão para subverter os ouvintes.");
    b->dados[TIMOTEO2].capitulos[2].versos[15] = wxT("Procura apresentar-te diante de Deus aprovado, como obreiro que não tem de que se envergonhar, que maneja bem a palavra da verdade.");
    b->dados[TIMOTEO2].capitulos[2].versos[16] = wxT("Mas evita as conversas vãs e profanas; porque os que delas usam passarão a impiedade ainda maior,");
    b->dados[TIMOTEO2].capitulos[2].versos[17] = wxT("e as suas palavras alastrarão como gangrena; entre os quais estão Himeneu e Fileto,");
    b->dados[TIMOTEO2].capitulos[2].versos[18] = wxT("que se desviaram da verdade, dizendo que a ressurreição é já passada, e assim pervertem a fé a alguns.");
    b->dados[TIMOTEO2].capitulos[2].versos[19] = wxT("Todavia o firme fundamento de Deus permanece, tendo este selo: O Senhor conhece os seus, e: Aparte-se da injustiça todo aquele que profere o nome do Senhor.");
    b->dados[TIMOTEO2].capitulos[2].versos[20] = wxT("Ora, numa grande casa, não somente há vasos de ouro e de prata, mas também de madeira e de barro; e uns, na verdade, para uso honroso, outros, porém, para uso desonroso.");
    b->dados[TIMOTEO2].capitulos[2].versos[21] = wxT("Se, pois, alguém se purificar destas coisas, será vaso para honra, santificado e útil ao Senhor, preparado para toda boa obra.");
    b->dados[TIMOTEO2].capitulos[2].versos[22] = wxT("Foge também das paixões da mocidade, e segue a justiça, a fé, o amor, a paz com os que, de coração puro, invocam o Senhor.");
    b->dados[TIMOTEO2].capitulos[2].versos[23] = wxT("E rejeita as questões tolas e desassisadas, sabendo que geram contendas;");
    b->dados[TIMOTEO2].capitulos[2].versos[24] = wxT("e ao servo do Senhor não convém contender, mas sim ser brando para com todos, apto para ensinar, paciente;");
    b->dados[TIMOTEO2].capitulos[2].versos[25] = wxT("corrigindo com mansidão os que resistem, na esperança de que Deus lhes conceda o arrependimento para conhecerem plenamente a verdade,");
    b->dados[TIMOTEO2].capitulos[2].versos[26] = wxT("e que se desprendam dos laços do Diabo {por quem haviam sido presos}, para cumprirem a vontade de Deus.");

    b->dados[TIMOTEO2].capitulos[3].versos[1] = wxT("Sabe, porém, isto, que nos últimos dias sobrevirão tempos penosos;");
    b->dados[TIMOTEO2].capitulos[3].versos[2] = wxT("pois os homens serão amantes de si mesmos, gananciosos, presunçosos, soberbos, blasfemos, desobedientes a seus pais, ingratos, ímpios,");
    b->dados[TIMOTEO2].capitulos[3].versos[3] = wxT("sem afeição natural, implacáveis, caluniadores, incontinentes, cruéis, inimigos do bem,");
    b->dados[TIMOTEO2].capitulos[3].versos[4] = wxT("traidores, atrevidos, orgulhosos, mais amigos dos deleites do que amigos de Deus,");
    b->dados[TIMOTEO2].capitulos[3].versos[5] = wxT("tendo aparência de piedade, mas negando-lhe o poder. Afasta-te também desses.");
    b->dados[TIMOTEO2].capitulos[3].versos[6] = wxT("Porque deste número são os que se introduzem pelas casas, e levam cativas mulheres néscias carregadas de pecados, levadas de várias concupiscências;");
    b->dados[TIMOTEO2].capitulos[3].versos[7] = wxT("sempre aprendendo, mas nunca podendo chegar ao pleno conhecimento da verdade.");
    b->dados[TIMOTEO2].capitulos[3].versos[8] = wxT("E assim como Janes e Jambres resistiram a Moisés, assim também estes resistem à verdade, sendo homens corruptos de entendimento e réprobos quanto à fé.");
    b->dados[TIMOTEO2].capitulos[3].versos[9] = wxT("Não irão, porém, avante; porque a todos será manifesta a sua insensatez, como também o foi a daqueles.");
    b->dados[TIMOTEO2].capitulos[3].versos[10] = wxT("Tu, porém, tens observado a minha doutrina, procedimento, intenção, fé, longanimidade, amor, perseverança,");
    b->dados[TIMOTEO2].capitulos[3].versos[11] = wxT("as minhas perseguições e aflições, quais as que sofri em Antioquia, em Icônio, em Listra; quantas perseguições suportei! e de todas o Senhor me livrou.");
    b->dados[TIMOTEO2].capitulos[3].versos[12] = wxT("E na verdade todos os que querem viver piamente em Cristo Jesus padecerão perseguições.");
    b->dados[TIMOTEO2].capitulos[3].versos[13] = wxT("Mas os homens maus e impostores irão de mal a pior, enganando e sendo enganados.");
    b->dados[TIMOTEO2].capitulos[3].versos[14] = wxT("Tu, porém, permanece naquilo que aprendeste, e de que foste inteirado, sabendo de quem o tens aprendido,");
    b->dados[TIMOTEO2].capitulos[3].versos[15] = wxT("e que desde a infância sabes as sagradas letras, que podem fazer-te sábio para a salvação, pela que há em Cristo Jesus.");
    b->dados[TIMOTEO2].capitulos[3].versos[16] = wxT("Toda Escritura é divinamente inspirada e proveitosa para ensinar, para repreender, para corrigir, para instruir em justiça;");
    b->dados[TIMOTEO2].capitulos[3].versos[17] = wxT("para que o homem de Deus seja perfeito, e perfeitamente preparado para toda boa obra.");

    b->dados[TIMOTEO2].capitulos[4].versos[1] = wxT("Conjuro-te diante de Deus e de Cristo Jesus, que há de julgar os vivos e os mortos, pela sua vinda e pelo seu reino;");
    b->dados[TIMOTEO2].capitulos[4].versos[2] = wxT("prega a palavra, insta a tempo e fora de tempo, admoesta, repreende, exorta, com toda longanimidade e ensino.");
    b->dados[TIMOTEO2].capitulos[4].versos[3] = wxT("Porque virá tempo em que não suportarão a sã doutrina; mas, tendo grande desejo de ouvir coisas agradáveis, ajuntarão para si mestres segundo os seus próprios desejos,");
    b->dados[TIMOTEO2].capitulos[4].versos[4] = wxT("e não só desviarão os ouvidos da verdade, mas se voltarão às fábulas.");
    b->dados[TIMOTEO2].capitulos[4].versos[5] = wxT("Tu, porém, sê sóbrio em tudo, sofre as aflições, faze a obra de um evangelista, cumpre o teu ministério.");
    b->dados[TIMOTEO2].capitulos[4].versos[6] = wxT("Quanto a mim, já estou sendo derramado como libação, e o tempo da minha partida está próximo.");
    b->dados[TIMOTEO2].capitulos[4].versos[7] = wxT("Combati o bom combate, acabei a carreira, guardei a fé.");
    b->dados[TIMOTEO2].capitulos[4].versos[8] = wxT("Desde agora, a coroa da justiça me está guardada, a qual o Senhor, justo juiz, me dará naquele dia; e não somente a mim, mas também a todos os que amarem a sua vinda.");
    b->dados[TIMOTEO2].capitulos[4].versos[9] = wxT("Procura vir ter comigo breve;");
    b->dados[TIMOTEO2].capitulos[4].versos[10] = wxT("pois Demas me abandonou, tendo amado o mundo presente, e foi para Tessalônica, Crescente para a Galácia, Tito para a Dalmácia;");
    b->dados[TIMOTEO2].capitulos[4].versos[11] = wxT("só Lucas está comigo. Toma a Marcos e traze-o contigo, porque me é muito útil para o ministério.");
    b->dados[TIMOTEO2].capitulos[4].versos[12] = wxT("Quanto a Tíquico, enviei-o a Éfeso.");
    b->dados[TIMOTEO2].capitulos[4].versos[13] = wxT("Quando vieres traze a capa que deixei em Trôade, em casa de Carpo, e os livros, especialmente os pergaminhos.");
    b->dados[TIMOTEO2].capitulos[4].versos[14] = wxT("Alexandre, o latoeiro, me fez muito mal; o Senhor lhe retribuirá segundo as suas obras.");
    b->dados[TIMOTEO2].capitulos[4].versos[15] = wxT("Tu também guarda-te dele; porque resistiu muito às nossas palavras.");
    b->dados[TIMOTEO2].capitulos[4].versos[16] = wxT("Na minha primeira defesa ninguém me assistiu, antes todos me desampararam. Que isto não lhes seja imputado.");
    b->dados[TIMOTEO2].capitulos[4].versos[17] = wxT("Mas o Senhor esteve ao meu lado e me fortaleceu, para que por mim fosse cumprida a pregação, e a ouvissem todos os gentios; e fiquei livre da boca do leão,");
    b->dados[TIMOTEO2].capitulos[4].versos[18] = wxT("E o Senhor me livrará de toda má obra, e me levará salvo para o seu reino celestial; a quem seja glória para todo o sempre. Amém.");
    b->dados[TIMOTEO2].capitulos[4].versos[19] = wxT("Saúda a Prisca e a Áquila e à casa de Onesíforo.");
    b->dados[TIMOTEO2].capitulos[4].versos[20] = wxT("Erasto ficou em Corinto; a Trófimo deixei doente em Mileto.");
    b->dados[TIMOTEO2].capitulos[4].versos[21] = wxT("Apressa-te a vir antes do inverno. Saúdam-te Êubulo, Pudente, Lino, Cláudia, e todos os irmãos.");
    b->dados[TIMOTEO2].capitulos[4].versos[22] = wxT("O Senhor seja com o teu espírito. A graça seja convosco. ^Z");

}
